    ,('Alliance to Feed the Earth in Disasters', 'ALLFED', NULL, 'https://allfed.info/', 'https://allfed.info/about/team-and-board', 'info@allfed.info', 'United States', '2017-01-01', 'year', 'https://allfed.info/about/our-history', 'https://allfed.info/ https://allfed.info/about https://allfed.info/about/our-history https://allfed.info/about/team-and-board https://allfed.info/contact', 'Alliance to Feed the Earth in Disasters (ALLFED) is a nonprofit focused on ensuring global food resilience in catastrophic scenarios. Its core objectives are to identify, pilot, and prepare resilient food solutions, and to support governments and communities in implementing these solutions during global food shocks. Its research evaluates alternative food systems (e.g., microbial, cellulosic, and industrial production), scalability, cost, and nutritional adequacy across scenarios such as nuclear winter, extreme climate change, loss of electricity, industry, or transportation. ALLFED also engages with policymakers and institutions to improve preparedness for global catastrophic food failure (GCFF).', NULL, 'ALLFED', 'allfed', NULL, NULL, NULL, NULL, '@ALLFEDinfo', 'https://en.wikipedia.org/wiki/Alliance_to_Feed_the_Earth_in_Disasters', 'Alliance to Feed the Earth in Disasters')
