    ,('Atomic AI', NULL, NULL, 'https://atomic.ai/', 'https://atomic.ai/about/', 'info@atomic.ai', 'United States', '2022-01-01', 'year', 'https://atomic.ai/about/', 'https://atomic.ai/ https://atomic.ai/about/', 'Atomic AI is a biotechnology company focused on RNA-targeted drug discovery using artificial intelligence and structural biology. Its platform combines deep learning models with in-house wet-lab assays to predict RNA three-dimensional structure and design RNA-targeted small molecules and therapeutics. Its foundation model (ATOM-1) enables high-precision RNA structure prediction, expanding access to previously undruggable targets. The company operates at the intersection of machine learning and molecular biology to develop next-generation RNA-centric medicines.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
    ,('Ayuda Efectiva', NULL, NULL, 'https://ayudaefectiva.org/', 'https://ayudaefectiva.org/quienes-somos', 'info@ayudaefectiva.org', 'Spain', '2018-01-01', 'year', 'https://ayudaefectiva.org/quienes-somos', 'https://ayudaefectiva.org/ https://ayudaefectiva.org/quienes-somos https://substack.ayudaefectiva.org/ https://x.com/ayuda_efectiva https://www.instagram.com/ayuda_efectiva/ https://www.youtube.com/@ayuda_efectiva', 'Ayuda Efectiva is a Spanish nonprofit foundation that promotes evidence-based charitable giving by directing donations to the most cost-effective programs. Founded in 2018, it evaluates and funds interventions in areas such as global health, poverty alleviation, animal welfare, and climate change, relying on independent evaluators like GiveWell. It aims to maximize the impact of donations by helping donors allocate resources where they produce the greatest measurable benefit.', NULL, NULL, 'ayuda_efectiva', NULL, NULL, NULL, NULL, '@ayuda_efectiva', NULL, 'ayuda_efectiva')
