    ,('Frente Animal', NULL, NULL, 'https://www.frenteanimal.com/en/', 'https://www.frenteanimal.com/en/about/#team', NULL, 'Portugal', NULL, NULL, NULL, 'https://www.frenteanimal.com/en/ https://www.frenteanimal.com/en/about/#team https://www.facebook.com/frenteanimal https://x.com/orgfrenteanimal https://www.instagram.com/frenteanimalorg/ https://www.tiktok.com/@frenteanimal https://www.youtube.com/@frenteanimal', 'Frente Animal is a Portugal-based animal advocacy organization focused on improving the welfare of farmed animals. It conducts research on livestock production, runs corporate and political campaigns, and promotes public policies and technologies that reduce or replace animal use. Its work includes educational outreach, corporate engagement (e.g., promoting the European Chicken Commitment), and advocacy to increase awareness of animal sentience and welfare.', NULL, 'frenteanimal', 'frenteanimalorg', NULL, NULL, NULL, NULL, '@orgfrenteanimal', NULL, 'frenteanimal')
